// PROJECT MODAL — gallery shows your fixed screenshots
// ============================================================
function ProjectModal({ project, onClose }) {
  useEffect(() => {
    const handler = e => { if (e.key === 'Escape') onClose(); };
    document.addEventListener('keydown', handler);
    document.body.style.overflow = 'hidden';
    return () => { document.removeEventListener('keydown', handler); document.body.style.overflow = ''; };
  }, [onClose]);

  return (
    <div className="modal-overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="modal-box">
        <div className="modal-header">
          <div>
            <h2>{project.title}</h2>
            <p style={{ fontSize: '0.82rem', color: 'var(--text-light)', marginTop: 4 }}>{project.subtitle}</p>
          </div>
          <button className="modal-close" onClick={onClose}>✕</button>
        </div>
        <div className="modal-body">
          {/* SCREENSHOTS GALLERY */}
          {project.screenshots && project.screenshots.length > 0 ? (
            <div className="modal-gallery">
              {project.screenshots.map((src, i) => (
                <div key={i} className="gallery-item">
                  <img src={src} alt={`Screenshot ${i + 1}`} />
                </div>
              ))}
            </div>
          ) : (
            /* Shown when no screenshots added yet */
            <div className="gallery-placeholder">
              <Icon d={ICONS.img} size={40} />
              <p>Project screenshots coming soon!</p>
              <small>To add screenshots: put images in <strong>public/projects/</strong> and list them in <strong>App.js → projects → screenshots</strong></small>
            </div>
          )}

          {/* PROJECT INFO */}
          <div className="modal-project-info">
            <div className="modal-tech-tags">
              {project.tags.map((t, i) => <span key={i} className="modal-tech-tag">{t}</span>)}
            </div>
            <p>{project.fullDesc}</p>
            <div className="modal-features">
              <h4>Key Features</h4>
              <ul>{project.features.map((f, i) => <li key={i}>{f}</li>)}</ul>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

